        const fallback = VN_THEME_PRESETS[normalized.preset] || VN_THEME_PRESETS.genshin;
        normalized.nameAlign = normalized.nameAlign === 'left' ? 'left' : (normalized.nameAlign === 'center' ? 'center' : fallback.nameAlign);
